solutions.python:
class Solution:
    def getSum(self, a, b):
        mask = 0xFFFFFFFF
        while b & mask:
            carry = (a & b) << 1
            a = a ^ b
            b = carry
        a &= mask
        if a >> 31:
            a = ~(a ^ mask)
        return a

